const fetchTransactions = async () => {
  try {
    const res = await API.get("/transactions");
    console.log("Transactions API:", res.data); // 👈 ADD THIS
    setTransactions(res.data);
  } catch (err) {
    console.log(err);
  }
};

export default Transactions;
